code.body:
@_tool_decorator(return_direct={{params.return_direct}})
{{params.code}}
{{outputs.tool}} = {{params.name}}

try:
    if "{{params.format}}" == "json":
        {{outputs.parsed}} = json.loads({{inputs.raw_result}}) if isinstance({{inputs.raw_result}}, str) else {{inputs.raw_result}}
 "else":
        {{outputs.parsed}} = {"text": str({{inputs.raw_result}})}
    {{outputs.is_valid}} = True
except Exception:
    {{outputs.parsed}} = {"error": str({{inputs.raw_result}})}
    {{outputs.is_valid}} = False

_llm = ChatOpenAI(model="{{params.model}}", temperature=0)
_response = _llm.invoke({{inputs.state}}["messages"])
{{outputs.action}} = {"tool": _response.tool_calls[0]["name"], "input": _response.tool_calls[0]["args"]} if _response.tool_calls else {"tool": "final_answer", "input": _response.content}
{{outputs.observation}} = str({{outputs.action}})
{{outputs.next_state}} = {**{{inputs.state}}, "last_action": {{outputs.action}}}

{{outputs.waveform}}, {{outputs.sample_rate}} = torchaudio.load({{inputs.file_path}}, backend="{{params.backend}}")
if {{params.mono}} and {{outputs.waveform}}.shape[0] > 1:
    {{outputs.waveform}} = {{outputs.waveform}}.mean(dim=0, keepdim=True)
if {{params.normalize}}:
    {{outputs.waveform}} = {{outputs.waveform}} / ({{outputs.waveform}}.abs().max() + 1e-8)

_mfcc_transform = T.MFCC(
    sample_rate=int({{inputs.sample_rate}}),
    n_mfcc={{params.n_mfcc}},
    melkwargs={"n_fft": {{params.n_fft}}, "hop_length": {{params.hop_length}}, "n_mels": {{params.n_mels}}}
)
{{outputs.mfcc}} = _mfcc_transform({{inputs.waveform}})

_diar_pipeline = Pipeline.from_pretrained("pyannote/speaker-diarization-3.1", use_auth_token="{{params.hf_token}}" or None)
_num_spk = {{params.num_speakers}} if {{params.num_speakers}} > 0 else None
{{outputs.diarization}} = _diar_pipeline({{inputs.file_path}}, num_speakers=_num_spk)
{{outputs.segments}} = [
    {"start": turn.start, "end": turn.end, "speaker": speaker}
    for turn, _, speaker in {{outputs.diarization}}.itertracks(yield_label=True)
]

_variant = "{{params.variant}}"
if _variant == "gaussian":
    {{outputs.model}} = GaussianNB(var_smoothing={{params.var_smoothing}})
elif _variant == "multinomial":
    {{outputs.model}} = MultinomialNB(alpha={{params.alpha}})
elif _variant == "bernoulli":
    {{outputs.model}} = BernoulliNB(alpha={{params.alpha}})
 "else":
    {{outputs.model}} = ComplementNB(alpha={{params.alpha}})
{{outputs.model}}.fit({{inputs.X_train}}, {{inputs.y_train}})

_max_eps = np.inf if {{params.max_eps}} == float("inf") else {{params.max_eps}}
{{outputs.model}} = OPTICS(min_samples={{params.min_samples}}, max_eps=_max_eps, metric="{{params.metric}}", cluster_method="{{params.cluster_method}}")
{{outputs.labels}} = {{outputs.model}}.fit_predict({{inputs.X}})

if {{params.condition_expr}}:
    {{branches.if_body}}
else:
    {{branches.else_body}}

match {{params.match_expr}}:
    {{#each params.cases}}
    case {{this}}:
        {{branches.[this]}}
    {{/each}}
    case _:
        {{branches.default_body}}

_iter_count_ = 0
while {{params.condition_expr}} and _iter_count_ < {{params.max_iterations}}:
    {{branches.loop_body}}
    _iter_count_ += 1

try:
    {{branches.try_body}}
except ({{params.exception_types}}) as _err_:
    {{branches.except_body}}
{{#if params.include_finally}}
finally:
    {{branches.finally_body}}
{{/if}}

{{#if (eq params.mode 'delay')}}time.sleep({{params.seconds}})
_elapsed_ = {{params.seconds}}{{else}}_t_start_ = time.perf_counter()
{{branches.timed_body}}
_elapsed_ = time.perf_counter() - _t_start_{{/if}}

{{outputs.image}} = Image.open("{{params.file_path}}").convert("{{params.mode}}")
if {{params.resize_w}} > 0 and {{params.resize_h}} > 0:
    {{outputs.image}} = {{outputs.image}}.resize(({{params.resize_w}}, {{params.resize_h}}))

{{outputs.waveform}}, {{outputs.sample_rate}} = torchaudio.load("{{params.file_path}}")
if {{params.mono}} and {{outputs.waveform}}.shape[0] > 1:
    {{outputs.waveform}} = {{outputs.waveform}}.mean(dim=0, keepdim=True)
if {{params.target_sr}} > 0 and {{outputs.sample_rate}} != {{params.target_sr}}:
    {{outputs.waveform}} = T.Resample({{outputs.sample_rate}}, {{params.target_sr}})({{outputs.waveform}})
    {{outputs.sample_rate}} = {{params.target_sr}}

_source = open("{{params.file_path}}", "r") if "{{params.file_path}}" != "-" else sys.stdin
{{outputs.lines}} = []
_count = 0
for _line in _source:
    {{outputs.lines}}.append(_line.rstrip("\\n"))
    _count += 1
    if {{params.max_lines}} > 0 and _count >= {{params.max_lines}}:
        break
if "{{params.file_path}}" != "-":
    _source.close()

{{outputs.file_path}} = "{{params.file_path}}"
if "{{params.format}}" == "csv":
    {{inputs.dataframe}}.to_csv({{outputs.file_path}}, index={{params.index}})
elif "{{params.format}}" == "json":
    {{inputs.dataframe}}.to_json({{outputs.file_path}}, orient="records", indent=2)
elif "{{params.format}}" == "parquet":
    {{inputs.dataframe}}.to_parquet({{outputs.file_path}}, index={{params.index}})
elif "{{params.format}}" == "excel":
    {{inputs.dataframe}}.to_excel({{outputs.file_path}}, index={{params.index}})

{{outputs.filtered}} = {{inputs.dataframe}}.query("{{params.expression}}")
if {{params.drop_index}}:
    {{outputs.filtered}} = {{outputs.filtered}}.reset_index(drop=True)

_strategy = "{{params.strategy}}"
_cols = [c.strip() for c in "{{params.columns}}".split(",") if c.strip()] or {{inputs.dataframe}}.columns.tolist()
{{outputs.filled}} = {{inputs.dataframe}}.copy()
for _col in _cols:
    if _strategy == "constant":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].fillna({{params.fill_value}})
    elif _strategy == "mean":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].fillna({{outputs.filled}}[_col].mean())
    elif _strategy == "median":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].fillna({{outputs.filled}}[_col].median())
    elif _strategy == "mode":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].fillna({{outputs.filled}}[_col].mode().iloc[0])
    elif _strategy == "ffill":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].ffill()
    elif _strategy == "bfill":
        {{outputs.filled}}[_col] = {{outputs.filled}}[_col].bfill()

_train_ratio = {{params.train_ratio}}
_val_ratio = {{params.val_ratio}}
_test_ratio = {{params.test_ratio}}
{{outputs.train}}, _temp = train_test_split({{inputs.dataframe}}, test_size=1 - _train_ratio, random_state={{params.random_state}}, shuffle={{params.shuffle}})
_relative_val = _val_ratio / (_val_ratio + _test_ratio)
{{outputs.val}}, {{outputs.test}} = train_test_split(_temp, test_size=1 - _relative_val, random_state={{params.random_state}}, shuffle={{params.shuffle}})
{{outputs.train}} = {{outputs.train}}.reset_index(drop=True)
{{outputs.val}} = {{outputs.val}}.reset_index(drop=True)
{{outputs.test}} = {{outputs.test}}.reset_index(drop=True)

_n = len({{inputs.dataframe}})
_bs = {{params.batch_size}}
{{outputs.batches}} = [{{inputs.dataframe}}.iloc[i:i+_bs].reset_index(drop=True) for i in range(0, _n, _bs)]
if {{params.drop_last}} and len({{outputs.batches}}) > 0 and len({{outputs.batches}}[-1]) < _bs:
    {{outputs.batches}} = {{outputs.batches}}[:-1]

_ws = {{params.window_size}}
_stride = {{params.stride}}
_n = len({{inputs.dataframe}})
{{outputs.windows}} = [{{inputs.dataframe}}.iloc[i:i+_ws].reset_index(drop=True) for i in range(0, _n - _ws + 1, _stride)]

_device = torch.device("cuda" if torch.cuda.is_available() else "cpu") if "{{params.device}}" == "auto" else torch.device("{{params.device}}")
{{inputs.model}}.to(_device)
if {{params.freeze}}:
    for _p in {{inputs.model}}.parameters():
        _p.requires_grad = False
{{inputs.model}}.eval()
{{outputs.teacher}} = {{inputs.model}}

_T = {{params.temperature}}
_alpha = {{params.alpha}}
_soft_student = F.log_softmax({{inputs.student_logits}} / _T, dim=-1)
_soft_teacher = F.softmax({{inputs.teacher_logits}} / _T, dim=-1)
_kd_loss = F.kl_div(_soft_student, _soft_teacher, reduction="batchmean") * (_T * _T)
if {{inputs.hard_labels}} is not None:
    _hard_loss = F.cross_entropy({{inputs.student_logits}}, {{inputs.hard_labels}})
    {{outputs.loss}} = _alpha * _kd_loss + (1 - _alpha) * _hard_loss
 "else":
    {{outputs.loss}} = _kd_loss

_s = {{inputs.student_features}}
_t = {{inputs.teacher_features}}
if {{params.normalize}}:
    _s = F.normalize(_s, dim=-1)
    _t = F.normalize(_t, dim=-1)
if "{{params.loss_type}}" == "mse":
    {{outputs.loss}} = F.mse_loss(_s, _t)
elif "{{params.loss_type}}" == "l1":
    {{outputs.loss}} = F.l1_loss(_s, _t)
 "else":
    {{outputs.loss}} = (1 - F.cosine_similarity(_s, _t, dim=-1)).mean()

for _name, _module in {{inputs.model}}.named_modules():
    if isinstance(_module, (torch.nn.Conv2d, torch.nn.Linear)):
        prune.ln_structured(_module, name="weight", amount={{params.amount}}, n={{params.norm}}, dim=0)
        prune.remove(_module, "weight")
{{outputs.pruned_model}} = {{inputs.model}}

for _name, _module in {{inputs.model}}.named_modules():
    if isinstance(_module, (torch.nn.Conv2d, torch.nn.Linear)):
        prune.l1_unstructured(_module, name="weight", amount={{params.amount}})
        prune.remove(_module, "weight")
_total, _zeros = 0, 0
for _p in {{inputs.model}}.parameters():
    _total += _p.numel()
    _zeros += (_p == 0).sum().item()
{{outputs.sparsity}} = _zeros / _total
{{outputs.pruned_model}} = {{inputs.model}}

_params_to_prune = []
for _name, _module in {{inputs.model}}.named_modules():
    if isinstance(_module, (torch.nn.Conv2d, torch.nn.Linear)):
        _params_to_prune.append((_module, "weight"))
prune.global_unstructured(_params_to_prune, pruning_method=prune.L1Unstructured, amount={{params.amount}})
for _module, _pname in _params_to_prune:
    prune.remove(_module, _pname)
{{outputs.pruned_model}} = {{inputs.model}}

_initial_weights = { "n": p.clone() for n, p in {{inputs.model}}.named_parameters() if "weight" in n}
{{inputs.model}}.train()
_step = 0
for _x, _y in {{inputs.dataloader}}:
    _preds = {{inputs.model}}(_x)
    _loss = {{inputs.loss_fn}}(_preds, _y)
    {{inputs.optimizer}}.zero_grad()
    _loss.backward()
    {{inputs.optimizer}}.step()
    _step += 1
    if _step >= {{params.warmup_steps}}:
        break
_movements = {}
for _n, _p in {{inputs.model}}.named_parameters():
    if _n in _initial_weights:
        _movements[_n] = (_p.data - _initial_weights[_n]).abs()
_all_mvmt = torch.cat([m.flatten() for m in _movements.values()])
_threshold = torch.quantile(_all_mvmt, {{params.amount}})
for _n, _p in {{inputs.model}}.named_parameters():
    if _n in _movements:
        _mask = (_movements[_n] > _threshold).float()
        _p.data *= _mask
{{outputs.pruned_model}} = {{inputs.model}}

_init_state = copy.deepcopy({{inputs.model}}.state_dict())
_masks = {}
for _round in range({{params.rounds}}):
    {{inputs.model}}.load_state_dict(_init_state)
    for _n, _m in _masks.items():
        dict({{inputs.model}}.named_parameters())[_n].data *= _m
    _opt = torch.optim.SGD({{inputs.model}}.parameters(), lr={{params.lr}})
    {{inputs.model}}.train()
    _step = 0
    for _x, _y in {{inputs.dataloader}}:
        _loss = {{inputs.loss_fn}}({{inputs.model}}(_x), _y)
        _opt.zero_grad()
        _loss.backward()
        _opt.step()
        _step += 1
        if _step >= {{params.train_steps}}:
            break
    for _n, _p in {{inputs.model}}.named_parameters():
        if "weight" in _n:
            _thresh = torch.quantile(_p.data.abs().flatten(), {{params.prune_rate}})
            _new_mask = (_p.data.abs() > _thresh).float()
            _masks[_n] = _masks.get(_n, torch.ones_like(_p.data)) * _new_mask
{{outputs.mask}} = _masks
{{inputs.model}}.load_state_dict(_init_state)
for _n, _m in _masks.items():
    dict({{inputs.model}}.named_parameters())[_n].data *= _m
{{outputs.model_out}} = {{inputs.model}}

for _name, _param in {{inputs.model}}.named_parameters():
    if "weight" in _name and _param.dim() >= 2:
        _w = _param.data.cpu().numpy().flatten()
        _kmeans = KMeans(n_clusters=min({{params.num_clusters}}, len(_w)), random_state=0, n_init=10).fit(_w.reshape(-1, 1))
        _quantized = _kmeans.cluster_centers_[_kmeans.labels_].reshape(_param.shape)
        _param.data = torch.tensor(_quantized, dtype=_param.dtype, device=_param.device)
{{outputs.compressed_model}} = {{inputs.model}}

_query = {{inputs.query}}
_words = _query.lower().split()
{{outputs.added_terms}} = []
if "{{params.method}}" == "wordnet":
    for _word in _words:
        _syns = set()
        for _ss in wordnet.synsets(_word):
            for _lemma in _ss.lemmas():
                _name = _lemma.name().replace("_", " ")
                if _name.lower() != _word:
                    _syns.add(_name)
                if len(_syns) >= {{params.max_synonyms_per_word}}:
                    break
            if len(_syns) >= {{params.max_synonyms_per_word}}:
                break
        {{outputs.added_terms}}.extend(list(_syns))
 "else":
    from sentence_transformers import SentenceTransformer
    import numpy as np
    _model = SentenceTransformer("{{params.embed_model}}")
    _word_embs = _model.encode(_words)
    # Use model vocabulary to find nearest terms (simplified)
    _all_terms = list(set(_words))
    for _word in _words:
        _w_emb = _model.encode([_word])
        _sims = np.dot(_model.encode(_all_terms), _w_emb.T).flatten()
        _top = np.argsort(-_sims)[1:{{params.max_synonyms_per_word}}+1]
        {{outputs.added_terms}}.extend([_all_terms[i] for i in _top if _all_terms[i] != _word])
{{outputs.expanded_query}} = _query + " " + " ".join({{outputs.added_terms}})

_parent_splitter = RecursiveCharacterTextSplitter(
    chunk_size={{params.parent_chunk_size}}, chunk_overlap=0
)
_child_splitter = RecursiveCharacterTextSplitter(
    chunk_size={{params.child_chunk_size}},
    chunk_overlap={{params.child_overlap}}
)
{{outputs.parent_chunks}} = _parent_splitter.split_text({{inputs.text}})
{{outputs.child_chunks}} = []
{{outputs.child_to_parent}} = []
for _pidx, _parent in enumerate({{outputs.parent_chunks}}):
    _children = _child_splitter.split_text(_parent)
    for _child in _children:
        {{outputs.child_chunks}}.append(_child)
        {{outputs.child_to_parent}}.append(_pidx)

_scorer = rouge_scorer.RougeScorer({{params.rouge_types}}, use_stemmer=True)
_agg = { "k": [] for k in {{params.rouge_types}}}
for _ref, _hyp in zip({{inputs.references}}, {{inputs.hypotheses}}):
    _s = _scorer.score(_ref, _hyp)
    for _k in {{params.rouge_types}}:
        _agg[_k].append(_s[_k].fmeasure)
{{outputs.scores}} = { "_k": sum(_v) / len(_v) for _k, _v in _agg.items()}

def _pass_at_k(n, c, k):
    if n - c < k:
        return 1.0
    return 1.0 - comb(n - c, k) / comb(n, k)
_scores = [_pass_at_k(int(n), int(c), {{params.k}}) for n, c in zip({{inputs.num_samples}}, {{inputs.num_correct}})]
{{outputs.score}} = np.mean(_scores).item()

_y_true = np.array({{inputs.y_true}})
_y_pred = np.array({{inputs.y_pred}})
_report = {}
for _col in {{inputs.sensitive_features}}.columns:
    _groups = {{inputs.sensitive_features}}[_col].unique()
    _col_report = {}
    for _g in _groups:
        _mask = ({{inputs.sensitive_features}}[_col] == _g).values
        _group_metrics = {}
        if "accuracy" in {{params.metrics}}:
            _group_metrics["accuracy"] = float(accuracy_score(_y_true[_mask], _y_pred[_mask]))
        if "selection_rate" in {{params.metrics}}:
            _group_metrics["selection_rate"] = float(_y_pred[_mask].mean())
        if "tpr" in {{params.metrics}}:
            _pos = _mask & (_y_true == 1)
            _group_metrics["tpr"] = float(_y_pred[_pos].mean()) if _pos.any() else 0.0
        if "fpr" in {{params.metrics}}:
            _neg = _mask & (_y_true == 0)
            _group_metrics["fpr"] = float(_y_pred[_neg].mean()) if _neg.any() else 0.0
        _col_report[str(_g)] = _group_metrics
    _report[_col] = _col_report
{{outputs.report}} = _report

if "{{params.format}}" == "json":
    with open({{inputs.annotations_path}}) as _f:
        _data = json.load(_f)
 "else":
    with open({{inputs.annotations_path}}) as _f:
        _data = list(csv.DictReader(_f))
_by_item = {}
for _ann in _data:
    _item_id = _ann["item_id"]
    if _item_id not in _by_item:
        _by_item[_item_id] = []
    _by_item[_item_id].append(float(_ann["score"]))
_agg = {}
for _item_id, _scores in _by_item.items():
    if "{{params.agg_method}}" == "mean":
        _agg[_item_id] = float(np.mean(_scores))
    elif "{{params.agg_method}}" == "median":
        _agg[_item_id] = float(np.median(_scores))
 "else":
        _vals, _counts = np.unique(_scores, return_counts=True)
        _agg[_item_id] = float(_vals[np.argmax(_counts)])
_pairs = [(s[0], s[1]) for s in _by_item.values() if len(s) >= 2]
if _pairs:
    _a1, _a2 = zip(*_pairs)
    {{outputs.agreement}} = float(cohen_kappa_score(np.round(_a1), np.round(_a2)))
 "else":
    {{outputs.agreement}} = 0.0
{{outputs.aggregated}} = _agg

_metrics_list = [m.strip() for m in "{{params.metrics}}".split(",")]
_rows = []
if "{{params.backend}}" == "mlflow":
    import mlflow
    for _rid in {{inputs.run_ids}}:
        _run = mlflow.get_run(_rid)
        _row = {"run_id": _rid, **{ "m": _run.data.metrics.get(m) for m in _metrics_list}, **_run.data.params}
        _rows.append(_row)
 "else":
    import wandb
    _api = wandb.Api()
    for _rid in {{inputs.run_ids}}:
        _run = _api.run(_rid)
        _row = {"run_id": _rid, **{ "m": _run.summary.get(m) for m in _metrics_list}, **dict(_run.config)}
        _rows.append(_row)
{{outputs.comparison}} = pd.DataFrame(_rows)

random.seed({{params.seed}})
_dists = json.loads('{{params.param_distributions}}')
def _sample(spec):
    if "choices" in spec:
        return random.choice(spec["choices"])
    _low, _high = spec["low"], spec["high"]
    if spec.get("log"):
        return math.exp(random.uniform(math.log(_low), math.log(_high)))
    return random.uniform(_low, _high)
_results = []
_best_val = float("inf") if "{{params.direction}}" == "minimize" else float("-inf")
_best_cfg = None
for _ in range({{params.n_trials}}):
    _cfg = { "k": _sample(v) for k, v in _dists.items()}
    _metric = {{inputs.train_fn}}(_cfg)
    _results.append({**_cfg, "{{params.metric_name}}": _metric})
    if ("{{params.direction}}" == "minimize" and _metric < _best_val) or ("{{params.direction}}" == "maximize" and _metric > _best_val):
        _best_val = _metric
        _best_cfg = _cfg
{{outputs.results}} = _results
{{outputs.best_config}} = _best_cfg

_space = json.loads('{{params.search_space}}')
_config = {}
for _p in _space:
    if _p["type"] == "float":
        _config[_p["name"]] = {{inputs.trial}}.suggest_float(_p["name"], _p["low"], _p["high"], log=_p.get("log", False))
    elif _p["type"] == "int":
        _config[_p["name"]] = {{inputs.trial}}.suggest_int(_p["name"], _p["low"], _p["high"], step=_p.get("step", 1))
    elif _p["type"] == "categorical":
        _config[_p["name"]] = {{inputs.trial}}.suggest_categorical(_p["name"], _p["choices"])
{{outputs.config}} = _config

_raw_space = json.loads('{{params.search_space}}')
_space = {}
for _k, _v in _raw_space.items():
    if _v["type"] == "loguniform":
        _space[_k] = tune.loguniform(_v["low"], _v["high"])
    elif _v["type"] == "uniform":
        _space[_k] = tune.uniform(_v["low"], _v["high"])
    elif _v["type"] == "choice":
        _space[_k] = tune.choice(_v["values"])
    elif _v["type"] == "randint":
        _space[_k] = tune.randint(_v["low"], _v["high"])
_scheduler = None
if "{{params.scheduler}}" == "asha":
    _scheduler = ASHAScheduler(metric="{{params.metric}}", mode="{{params.mode}}")
elif "{{params.scheduler}}" == "hyperband":
    _scheduler = HyperBandScheduler(metric="{{params.metric}}", mode="{{params.mode}}")
{{outputs.results}} = tune.run(
    {{inputs.train_fn}},
    config=_space,
    num_samples={{params.num_samples}},
    scheduler=_scheduler,
    resources_per_trial={"cpu": {{params.cpus_per_trial}}, "gpu": {{params.gpus_per_trial}}},
)
{{outputs.best_config}} = {{outputs.results}}.get_best_config(metric="{{params.metric}}", mode="{{params.mode}}")

for _name, _param in {{inputs.model}}.named_parameters():
    if "{{params.freeze_pattern}}" in _name:
        _param.requires_grad = False
{{outputs.trainable_params}} = sum(p.numel() for p in {{inputs.model}}.parameters() if p.requires_grad)
print(f"Trainable parameters: {{{outputs.trainable_params}}:}")
{{outputs.model_out}} = {{inputs.model}}

for _param in {{inputs.model}}.parameters():
    _param.requires_grad = False

class _LinearProbe(nn.Module):
    def __init__(self, backbone, hidden_dim, num_classes):
        super().__init__()
        self.backbone = backbone
        self.classifier = nn.Linear(hidden_dim, num_classes)
    def forward(self, x):
        with torch.no_grad():
            features = self.backbone(x)
            if hasattr(features, "last_hidden_state"):
                features = features.last_hidden_state[:, 0]
            elif hasattr(features, "pooler_output"):
                features = features.pooler_output
        return self.classifier(features)

import torch
{{outputs.probe_model}} = _LinearProbe({{inputs.model}}, {{params.hidden_dim}}, {{params.num_classes}})

for _name, _param in {{inputs.model}}.named_parameters():
    _param.requires_grad = False
    if "bias" in _name:
        _param.requires_grad = True
    if {{params.include_layernorm}} and ("LayerNorm" in _name or "layernorm" in _name or "layer_norm" in _name):
        _param.requires_grad = True
{{outputs.trainable_params}} = sum(p.numel() for p in {{inputs.model}}.parameters() if p.requires_grad)
_total_params = sum(p.numel() for p in {{inputs.model}}.parameters())
