    {{outputs.data}} = json.loads({{inputs.text}})
except json.JSONDecodeError:
    if {{params.strict}}:
        raise
    {{outputs.data}} = None

if "{{params.mode}}" == "encode":
    _data = {{inputs.data}}.encode() if isinstance({{inputs.data}}, str) else {{inputs.data}}
    {{outputs.result}} = (base64.urlsafe_b64encode(_data) if {{params.url_safe}} else base64.b64encode(_data)).decode()
 "else":
    {{outputs.result}} = (base64.urlsafe_b64decode({{inputs.data}}) if {{params.url_safe}} else base64.b64decode({{inputs.data}})).decode()

_comp = {"deflated": zipfile.ZIP_DEFLATED, "stored": zipfile.ZIP_STORED, "bzip2": zipfile.ZIP_BZIP2, "lzma": zipfile.ZIP_LZMA}
with zipfile.ZipFile("{{params.output_path}}", "w", _comp["{{params.compression}}"]) as _zf:
    for _fp in {{inputs.file_paths}}:
        _p = Path(_fp)
        if _p.is_dir():
            for _f in _p.rglob("*"):
                _zf.write(_f, _f.relative_to(_p.parent))
 "else":
            _zf.write(_p, _p.name)
{{outputs.zip_path}} = "{{params.output_path}}"

{{outputs.value}} = os.environ.get("{{params.name}}", "{{params.default}}")
if {{params.required}} and not {{outputs.value}}:
    raise EnvironmentError(f"Required environment variable '{{params.name}}' is not set")

_interp_map = {"bilinear": Image.BILINEAR, "nearest": Image.NEAREST, "bicubic": Image.BICUBIC, "lanczos": Image.LANCZOS}
_resize = transforms.Resize(({{params.height}}, {{params.width}}), interpolation=_interp_map["{{params.interpolation}}"])
{{outputs.image_out}} = _resize({{inputs.image}})

_augment_ops = []
if {{params.horizontal_flip}}:
    _augment_ops.append(transforms.RandomHorizontalFlip())
if {{params.vertical_flip}}:
    _augment_ops.append(transforms.RandomVerticalFlip())
if {{params.rotation_degrees}} > 0:
    _augment_ops.append(transforms.RandomRotation({{params.rotation_degrees}}))
if {{params.color_jitter}}:
    _augment_ops.append(transforms.ColorJitter(
        brightness={{params.brightness}}, contrast={{params.contrast}}, saturation={{params.saturation}}
    ))
_augment = transforms.Compose(_augment_ops)
{{outputs.image_out}} = _augment({{inputs.image}})
